/**
 * @param {number} n
 * @return {number[]}
 */
function solve(n) {
    // Map to store the sums and count how many distinct pairs generate them.
    // Key: sum (a^3 + b^3)
    // Value: Set of pairs (or just the count, but storing pairs can be safer if constraints were different, here count is enough)
    const sumsMap = new Map();

    // Determine the maximum possible value for 'a' and 'b'.
    // Since a^3 + b^3 <= n, and a <= b, then 2*a^3 <= a^3 + b^3 <= n.
    // a^3 <= n/2. Thus, a <= cubeRoot(n/2).
    // Similarly, b^3 <= n, so b <= cubeRoot(n).

    // Calculate the upper bound for 'a'. Since a <= b, a^3 + a^3 <= n => 2a^3 <= n => a^3 <= n/2
    const maxA = Math.floor(Math.cbrt(n / 2));

    // Iterate through possible values of 'a' (starting from 1)
    for (let a = 1; a <= maxA; a++) {
        const aCubed = a * a * a;

        // Iterate through possible values of 'b' (starting from 'a' to ensure a <= b)
        // b^3 <= n - a^3 => b <= cubeRoot(n - a^3)
        const maxB = Math.floor(Math.cbrt(n - aCubed));

        for (let b = a; b <= maxB; b++) {
            const bCubed = b * b * b;
            const sum = aCubed + bCubed;

            if (sum <= n) {
                if (!sumsMap.has(sum)) {
                    // Store the count of representations for this sum
                    sumsMap.set(sum, 1);
                } else {
                    // Increment the count of representations
                    sumsMap.set(sum, sumsMap.get(sum) + 1);
                }
            } else {
                // Since b is increasing, any further sums for this 'a' will exceed n.
                break;
            }
        }
    }

    const goodNumbers = [];

    // A number is "good" if it has at least two different pairs (a, b).
    for (const [sum, count] of sumsMap.entries()) {
        if (count >= 2) {
            goodNumbers.push(sum);
        }
    }

    // The problem requires the result to be sorted in ascending order.
    goodNumbers.sort((x, y) => x - y);

    return goodNumbers;
