import java.util.ArrayList;
import java.util.Collections;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

class Solution {
    /**
     * Finds all "good numbers" less than or equal to n.
     * A number x is "good" if there are at least two different pairs of positive integers (a, b)
     * such that a^3 + b^3 = x, with a <= b.
     * 
     * @param n The upper limit.
     * @return An array of good numbers less than or equal to n, sorted ascendingly.
     */
    public static long[] solve(long n) {
        // Map to store the sums and count how many distinct pairs generate them.
        // Key: sum (a^3 + b^3)
        // Value: count of representations
        Map<Long, Integer> sumsMap = new HashMap<>();

        // Determine the maximum possible value for 'a'.
        // Since a <= b, a^3 + a^3 <= n => 2*a^3 <= n => a^3 <= n/2
        // a <= cubeRoot(n/2)

        // We use Math.pow and casting for cube root approximation for large long inputs.
        // Since n <= 10^9, n/2 <= 5*10^8. The cube root is around 793.
        // A safe upper bound for a is when a^3 <= n. For n=10^9, max_a = 1000.

        // Calculate maxA such that a*a*a <= n/2
        long maxA = (long) Math.floor(Math.cbrt((double) n / 2.0));

        // Safety check for maxA calculation, ensuring maxA^3 <= n/2
        while ((maxA + 1) * (maxA + 1) * (maxA + 1) <= n / 2 && maxA < 200000) {
            maxA++;
        }


        // Iterate through possible values of 'a' (starting from 1)
        for (long a = 1; a <= maxA; a++) {
            long aCubed = a * a * a;

            // Iterate through possible values of 'b' (starting from 'a' to ensure a <= b)
            // b^3 <= n - a^3 => b <= cubeRoot(n - a^3)
            long remainingN = n - aCubed;
            if (remainingN < aCubed) {
                // This should ideally not happen if maxA is calculated correctly, but it's a safeguard.
                break;
            }

            // Calculate maxB such that b^3 <= remainingN
            long maxB = (long) Math.floor(Math.cbrt((double) remainingN));

            // Ensure we start b from a
            long startB = a;
            if (maxB < startB) {
                continue; // No valid b exists for this a
            }

            for (long b = startB; b <= maxB; b++) {
                long bCubed = b * b * b;
                long sum = aCubed + bCubed;

                if (sum <= n) {
                    // Increment the count of representations for this sum
                    sumsMap.put(sum, sumsMap.getOrDefault(sum, 0) + 1);
                } else {
                    // Since b is increasing, any further sums for this 'a' will exceed n.
                    break;
                }
            }
        }

        List<Long> goodNumbersList = new ArrayList<>();

        // A number is "good" if it has at least two different pairs (a, b).
        for (Map.Entry<Long, Integer> entry : sumsMap.entrySet()) {
            if (entry.getValue() >= 2) {
                goodNumbersList.add(entry.getKey());
            }
        }

        // The problem requires the result to be sorted in ascending order.
        Collections.sort(goodNumbersList);

        // Convert List<Long> to long[]
        long[] result = new long[goodNumbersList.size()];
        for (int i = 0; i < goodNumbersList.size(); i++) {
            result[i] = goodNumbersList.get(i);
        }

        return result;
    }
}
