import java.util.Map;

public class Solution {
    public static long[] solve(long n) {
        // Map to store the sums and count how many distinct pairs generate them.
        // Key: sum (a^3 + b^3)
        // Value: count of representations for this sum
        Map<Long, Integer> sumsMap = new HashMap<>();

        // Determine the maximum possible value for 'a'.
        // Since a <= b, 2*a^3 <= a^3 + b^3 <= n.
        // a^3 <= n/2. Thus, a <= cubeRoot(n/2).
        // We need to calculate the cube root of n/2. Since n is up to 10^9, n/2 is up to 5*10^8.
        // The cube root of 5*10^8 is around 793.

        // A safe way to find maxA: find the largest integer a such that 2*a^3 <= n.
        long maxA = 0;
        for (long a = 1; ; a++) {
            // Check if 2 * a^3 > n to stop. Use multiplication carefully to avoid overflow if n was much larger,
            // but for n <= 10^9, a^3 <= 5*10^8, 2*a^3 <= 10^9, which fits in a long.
            if (2L * a * a * a > n) {
                maxA = a - 1;
                break;
            }
            if (a * a * a > n && a > 1) { // Safety break if the loop runs too long (shouldn't happen)
                maxA = a - 1;
                break;
            }
        }

        // If n is very small, maxA might still be 0.
        if (n < 2) {
            return new long[0];
        }

        // If we can't find maxA robustly without floating point errors, we can iterate up to a safe upper bound (e.g., 1000 for n=10^9)
        // For N=10^9, maxA is around 793. Iterating up to 1000 is safe.
        if (maxA == 0) {
             maxA = (long) Math.ceil(Math.cbrt((double)n / 2.0));
        }


