                long estimateB = (long) Math.cbrt((double) remaining);

                // Adjust estimate to ensure b^3 <= remaining
                // Check slightly above and below the estimate to account for precision errors in Math.cbrt
                for (long b = Math.max(a, estimateB - 2); b <= estimateB + 2; b++) {
